1	import { randomUUID } from 'node:crypto';
2	
3	import { BadRequestException, Injectable, Logger } from '@nestjs/common';
4	
5	import { CacheService } from '@modules/cache/cache.service';
6	import { Namespaces } from '@modules/cache/types/cache.interface';
7	import { EnvConfigService } from '@modules/env-config/env-config.service';
8	import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
9	import { GithubRepoModel } from '@modules/github/db/github-repos.model';
10	import { GithubAppService } from '@modules/github/github-app.service';
11	import { GithubBackfillService } from '@modules/github/github-backfill.service';
12	import { IGithubInstallationBase } from '@modules/github/types/github-installation.interface';
13	
14	import { GITHUB_APP_NAME } from '@constants/env-variables.constant';
15	
16	interface IInstallStateValue {
17		companyId: string;
18		userId: string;
19	}
20	
21	const STATE_TTL_MS = 5 * 60 * 1000;
22	
23	@Injectable()
24	export class GithubInstallService {
25		private readonly logger = new Logger(GithubInstallService.name);
26	
27		constructor(
28			private readonly configService: EnvConfigService,
29			private readonly cacheService: CacheService,
30			private readonly githubAppService: GithubAppService,
31			private readonly githubInstallationModel: GithubInstallationModel,
32			private readonly githubRepoModel: GithubRepoModel,
33			private readonly backfillService: GithubBackfillService,
34		) {}
35	
36		async initiateConnect({
37			companyId,
38			userId,
39		}: {
40			companyId: string;
41			userId: string;
42		}): Promise<string> {
43			const state = randomUUID();
44	
45			await this.cacheService.set({
46				namespace: Namespaces.GITHUB_INSTALL_STATE,
47				key: state,
48				value: { companyId, userId } satisfies IInstallStateValue,
49				ttl: STATE_TTL_MS,
50			});
51	
52			const appName = this.configService.get<string>({ key: GITHUB_APP_NAME });
53			return `https://github.com/apps/${appName}/installations/new?state=${state}`;
54		}
55	
56		async handleCallback({
57			installationId,
58			state,
59		}: {
60			installationId: number;
61			state: string;
62		}): Promise<IGithubInstallationBase> {
63			const stateData = await this.cacheService.get<IInstallStateValue>({
64				namespace: Namespaces.GITHUB_INSTALL_STATE,
65				key: state,
66			});
67	
68			if (!stateData) {
69				throw new BadRequestException('Invalid or expired state token');
70			}
71	
72			await this.cacheService.deleteOne({
73				namespace: Namespaces.GITHUB_INSTALL_STATE,
74				key: state,
75			});
76	
77			const githubInstall = await this.githubAppService.getInstallation({ installationId });
78	
79			const installation = await this.githubInstallationModel.create({
80				data: {
81					company_id: stateData.companyId,
82					installation_id: installationId,
83					org_login: githubInstall.account.login,
84					org_id: githubInstall.account.id,
85				},
86			});
87	
88			void this.syncRepos({
89				installationId,
90				installationDbId: installation._id,
91			});
92	
93			void this.backfillService.triggerBackfill({
94				installationDbId: installation._id,
95				installationId,
96			});
97	
98			return installation;
99		}
100	
101		async disconnect({
102			installationDbId,
103			companyId,
104		}: {
105			installationDbId: string;
106			companyId: string;
107		}): Promise<void> {
108			await this.githubInstallationModel.markUninstalledByDbId({
109				id: installationDbId,
110				companyId,
111			});
112	
113			this.logger.debug(
114				`Disconnected installation ${installationDbId} for company ${companyId}`,
115			);
116		}
117	
118		private async syncRepos({
119			installationId,
120			installationDbId,
121		}: {
122			installationId: number;
123			installationDbId: string;
124		}): Promise<void> {
125			try {
126				const repos = await this.githubAppService.listInstallationRepos({ installationId });
127				await this.githubRepoModel.upsertMany({ installationId: installationDbId, repos });
128				this.logger.debug(
129					`Synced ${repos.length} repos for installation ${installationDbId}`,
130				);
131			} catch (error) {
132				this.logger.error(
133					`Failed to sync repos for installation ${installationDbId}: ${(error as Error).message}`,
134				);
135			}
136		}
137	}
