1	import { InjectQueue } from '@nestjs/bullmq';
2	import { Injectable, Logger } from '@nestjs/common';
3	import { Queue } from 'bullmq';
4	
5	import { GithubRepoModel } from '@modules/github/db/github-repos.model';
6	
7	@Injectable()
8	export class GithubBackfillService {
9		private readonly logger = new Logger(GithubBackfillService.name);
10	
11		constructor(
12			private readonly repoModel: GithubRepoModel,
13			@InjectQueue('github') private readonly githubQueue: Queue,
14		) {}
15	
16		async triggerBackfill({
17			installationDbId,
18			installationId,
19		}: {
20			installationDbId: string;
21			installationId: number;
22		}): Promise<void> {
23			try {
24				const repos = await this.repoModel.findByInstallationId({ installationId: installationDbId });
25				for (const repo of repos) {
26					await this.githubQueue.add(
27						'backfill_repo',
28						{
29							installationDbId,
30							installationId,
31							repoDbId: repo._id,
32							repoFullName: repo.full_name,
33						},
34						{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
35					);
36				}
37				this.logger.debug(`Enqueued backfill for ${repos.length} repos in installation ${installationDbId}`);
38			} catch (error) {
39				this.logger.error(`Failed to trigger backfill for installation ${installationDbId}: ${(error as Error).message}`);
40				throw error;
41			}
42		}
43	}
