122		private async handlePush({
123			installationDbId,
124			payload,
125		}: {
126			installationDbId: string;
127			payload: IGithubWebhookPushEvent;
128		}): Promise<void> {
129			const repo = await this.repoModel.findByGithubRepoId({
130				githubRepoId: payload.repository.id,
131			});
132	
133			if (!repo) {
134				this.logger.warn(`Repo not found for github_repo_id: ${payload.repository.id}`);
135				return;
136			}
137	
138			const distinctCommits = payload.commits.filter((c) => c.distinct);
139	
140			if (distinctCommits.length === 0) return;
141	
142			for (const commit of distinctCommits) {
143				if (commit.author.username) {
144					await this.contributorModel.upsert({
145						data: {
146							installation_id: installationDbId,
147							github_user_id: 0,
148							github_login: commit.author.username,
149							github_name: commit.author.name,
150							github_email: commit.author.email,
151						},
152					});
153				}
154			}
155	
156			const commits: IGithubCommitUpsert[] = distinctCommits.map((c) => ({
157				installation_id: installationDbId,
158				repo_id: repo._id,
159				sha: c.id,
160				message: c.message,
161				author_login: c.author.username ?? null,
162				author_name: c.author.name,
163				author_email: c.author.email,
164				committed_at: new Date(c.timestamp),
165				additions: 0,
166				deletions: 0,
167				is_merge_commit: (c.parents?.length ?? 0) > 1,
168			}));
169	
170			await this.commitModel.upsertMany({ commits });
171		}
