359		private async backfillCommits({
360			installationDbId,
361			repoDbId,
362			repoFullName,
363			owner,
364			repo,
365			token,
366		}: {
367			installationDbId: string;
368			repoDbId: string;
369			repoFullName: string;
370			owner: string;
371			repo: string;
372			token: string;
373		}): Promise<void> {
374			let page = 1;
375			const perPage = 100;
376			while (true) {
377				const { data: commits } = await this.httpService.axiosRef.get<IGithubApiCommit[]>(
378					`https://api.github.com/repos/${owner}/${repo}/commits`,
379					{
380						headers: {
381							Authorization: `token ${token}`,
382							Accept: 'application/vnd.github+json',
383							'X-GitHub-Api-Version': '2022-11-28',
384						},
385						params: { per_page: perPage, page },
386					},
387				);
388				if (commits.length === 0) break;
389				await this.commitModel.upsertMany({
390					commits: commits.map((c) => ({
391						installation_id: installationDbId,
392						repo_id: repoDbId,
393						sha: c.sha,
394						message: c.commit.message,
395						author_login: c.author?.login ?? null,
396						author_name: c.commit.author.name,
397						author_email: c.commit.author.email,
398						committed_at: new Date(c.commit.author.date),
399						additions: c.stats?.additions ?? 0,
400						deletions: c.stats?.deletions ?? 0,
401						is_merge_commit: c.parents.length > 1,
402					})),
403				});
404				if (commits.length < perPage) break;
405				page++;
406			}
407			this.logger.debug(`Backfilled commits for ${repoFullName}`);
408		}
