13	@Injectable()
14	export class GithubRepoModel {
15		private readonly logger = new Logger(GithubRepoModel.name);
16		private readonly tableName = TABLE_NAME_GITHUB_REPOS;
17	
18		constructor(
19			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
20			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
21		) {}
22	
23		async upsertMany({
24			installationId,
25			repos,
26		}: {
27			installationId: string;
28			repos: IGithubApiRepo[];
29		}): Promise<void> {
30			if (repos.length === 0) return;
31	
32			try {
33				const rows = repos.map((repo) => ({
34					_id: randomUUID(),
35					installation_id: installationId,
36					github_repo_id: repo.id,
37					name: repo.name,
38					full_name: repo.full_name,
39					private: repo.private,
40					default_branch: repo.default_branch,
41					created_at: this.knexWrite.fn.now(),
42					updated_at: this.knexWrite.fn.now(),
43				}));
44	
45				await this.knexWrite<IGithubRepoBase>(this.tableName)
46					.insert(rows)
47					.onConflict('github_repo_id')
48					.merge([
49						'installation_id',
50						'name',
51						'full_name',
52						'private',
53						'default_branch',
54						'updated_at',
55					]);
56	
57				this.logger.debug(
58					`Upserted ${repos.length} repos for installation ${installationId}`,
59				);
60			} catch (error) {
61				this.logger.error(
62					`Failed to upsert repos for installation ${installationId}: ${(error as Error).message}`,
63				);
64				throw error;
65			}
66		}
67	
68		async findByInstallationId({
69			installationId,
70		}: {
71			installationId: string;
72		}): Promise<IGithubRepoBase[]> {
73			try {
74				return await this.knexRead<IGithubRepoBase>(this.tableName)
75					.where({ installation_id: installationId })
76					.select('*');
77			} catch (error) {
78				this.logger.error(
79					`Failed to find repos for installation ${installationId}: ${(error as Error).message}`,
80				);
81				throw error;
82			}
83		}
84	
85		async findByGithubRepoId({
86			githubRepoId,
87		}: {
88			githubRepoId: number;
89		}): Promise<IGithubRepoBase | null> {
90			try {
91				const result = await this.knexRead<IGithubRepoBase>(this.tableName)
92					.where({ github_repo_id: githubRepoId })
93					.first();
94				return result ?? null;
95			} catch (error) {
96				this.logger.error(
97					`Failed to find repo by github_repo_id ${githubRepoId}: ${(error as Error).message}`,
98				);
99				throw error;
100			}
101		}
102	
103		async removeByGithubIds({
104			installationId,
105			githubRepoIds,
106		}: {
107			installationId: string;
108			githubRepoIds: number[];
109		}): Promise<void> {
110			if (githubRepoIds.length === 0) return;
111	
112			try {
113				await this.knexWrite<IGithubRepoBase>(this.tableName)
114					.where({ installation_id: installationId })
115					.whereIn('github_repo_id', githubRepoIds)
116					.delete();
117	
118				this.logger.debug(
119					`Removed ${githubRepoIds.length} repos from installation ${installationId}`,
120				);
121			} catch (error) {
122				this.logger.error(
123					`Failed to remove repos from installation ${installationId}: ${(error as Error).message}`,
124				);
125				throw error;
126			}
127		}
128	}
