import { getQueueToken } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { GithubRepoModel } from '@modules/github/db/github-repos.model';
import { GithubBackfillService } from '@modules/github/github-backfill.service';
import { IGithubRepoBase } from '@modules/github/types/github-repo.interface';

const mockRepo: IGithubRepoBase = {
	_id: 'repo-db-id-1',
	installation_id: 'install-db-id-1',
	github_repo_id: 111,
	name: 'api',
	full_name: 'acme/api',
	private: false,
	default_branch: 'main',
	synced_at: null,
	created_at: new Date(),
	updated_at: new Date(),
};

const mockRepoModel = { findByInstallationId: jest.fn() };
const mockQueue = { add: jest.fn() };

describe('GithubBackfillService', () => {
	let service: GithubBackfillService;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				GithubBackfillService,
				{ provide: GithubRepoModel, useValue: mockRepoModel },
				{ provide: getQueueToken('github'), useValue: mockQueue },
			],
		}).compile();

		service = module.get<GithubBackfillService>(GithubBackfillService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('triggerBackfill', () => {
		it('should enqueue one job per repo with name backfill_repo', async () => {
			mockRepoModel.findByInstallationId.mockResolvedValue([mockRepo]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.triggerBackfill({
				installationDbId: 'install-db-id-1',
				installationId: 999,
			});

			expect(mockQueue.add).toHaveBeenCalledTimes(1);
			expect(mockQueue.add).toHaveBeenCalledWith(
				'backfill_repo',
				{
					installationDbId: 'install-db-id-1',
					installationId: 999,
					repoDbId: mockRepo._id,
					repoFullName: mockRepo.full_name,
				},
				{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
			);
		});

		it('should enqueue zero jobs when no repos', async () => {
			mockRepoModel.findByInstallationId.mockResolvedValue([]);
			mockQueue.add.mockResolvedValue(undefined);

			await service.triggerBackfill({
				installationDbId: 'install-db-id-1',
				installationId: 999,
			});

			expect(mockQueue.add).not.toHaveBeenCalled();
		});

		it('should rethrow when repoModel throws', async () => {
			mockRepoModel.findByInstallationId.mockRejectedValue(new Error('db error'));

			await expect(
				service.triggerBackfill({ installationDbId: 'install-db-id-1', installationId: 999 }),
			).rejects.toThrow('db error');
		});

		it('should rethrow when queue.add throws', async () => {
			mockRepoModel.findByInstallationId.mockResolvedValue([mockRepo]);
			mockQueue.add.mockRejectedValue(new Error('queue error'));

			await expect(
				service.triggerBackfill({ installationDbId: 'install-db-id-1', installationId: 999 }),
			).rejects.toThrow('queue error');
		});
	});
});

