describe('backfill_repo', () => {
	const backfillJobData = {
		installationDbId: 'install-db-id-1',
		installationId: 999,
		repoDbId: 'repo-db-id-1',
		repoFullName: 'acme/api',
	};

	const makeApiCommit = (sha: string) => ({
		sha,
		commit: {
			message: 'fix: bug',
			author: { name: 'John', email: 'j@co.com', date: '2026-01-01T10:00:00Z' },
		},
		author: { login: 'john' },
		parents: [],
		stats: { additions: 5, deletions: 2 },
	});

	const makeApiPr = (id: number, number: number) => ({
		id,
		number,
		title: 'feat: pr',
		state: 'open',
		user: { login: 'john', id: 1 },
		draft: false,
		merged: false,
		additions: 10,
		deletions: 2,
		changed_files: 3,
		commits: 1,
		created_at: '2026-01-01T10:00:00Z',
		merged_at: null,
		closed_at: null,
	});

	it('should backfill commits and PRs for the repo', async () => {
		mockGithubAppService.getInstallationToken.mockResolvedValue('token-abc');

		mockHttpService.axiosRef.get
			.mockResolvedValueOnce({ data: [makeApiCommit('sha-1')] })
			.mockResolvedValueOnce({ data: [makeApiPr(1, 42)] })
			.mockResolvedValueOnce({ data: [] })
			.mockResolvedValueOnce({ data: [] });

		mockContributorModel.upsert.mockResolvedValue(undefined);
		mockCommitModel.upsertMany.mockResolvedValue(undefined);
		mockPullRequestModel.upsert.mockResolvedValue(mockPr);

		await processor.process(makeJob('backfill_repo', backfillJobData));

		expect(mockCommitModel.upsertMany).toHaveBeenCalled();
		expect(mockPullRequestModel.upsert).toHaveBeenCalled();
	});

	it('should backfill reviews and comments during PR backfill', async () => {
		mockGithubAppService.getInstallationToken.mockResolvedValue('token-abc');

		const apiReview = {
			id: 55,
			state: 'approved',
			user: { login: 'reviewer', id: 2 },
			submitted_at: '2026-01-01T12:00:00Z',
		};

		const apiComment = {
			id: 77,
			body: 'looks good',
			path: 'src/foo.ts',
			line: 10,
			user: { login: 'reviewer', id: 2 },
			created_at: '2026-01-01T13:00:00Z',
		};

		mockHttpService.axiosRef.get
			.mockResolvedValueOnce({ data: [] })
			.mockResolvedValueOnce({ data: [makeApiPr(1, 42)] })
			.mockResolvedValueOnce({ data: [apiReview] })
			.mockResolvedValueOnce({ data: [apiComment] });

		mockContributorModel.upsert.mockResolvedValue(undefined);
		mockCommitModel.upsertMany.mockResolvedValue(undefined);
		mockPullRequestModel.upsert.mockResolvedValue(mockPr);
		mockReviewModel.upsert.mockResolvedValue(undefined);
		mockReviewCommentModel.upsert.mockResolvedValue(undefined);

		await processor.process(makeJob('backfill_repo', backfillJobData));

		expect(mockReviewModel.upsert).toHaveBeenCalled();
		expect(mockReviewCommentModel.upsert).toHaveBeenCalled();
	});

	it('should skip invalid review states during backfill', async () => {
		mockGithubAppService.getInstallationToken.mockResolvedValue('token-abc');

		const pendingReview = {
			id: 66,
			state: 'pending',
			user: { login: 'reviewer', id: 2 },
			submitted_at: '2026-01-01T12:00:00Z',
		};

		mockHttpService.axiosRef.get
			.mockResolvedValueOnce({ data: [] })
			.mockResolvedValueOnce({ data: [makeApiPr(1, 42)] })
			.mockResolvedValueOnce({ data: [pendingReview] })
			.mockResolvedValueOnce({ data: [] });

		mockContributorModel.upsert.mockResolvedValue(undefined);
		mockPullRequestModel.upsert.mockResolvedValue(mockPr);

		await processor.process(makeJob('backfill_repo', backfillJobData));

		expect(mockReviewModel.upsert).not.toHaveBeenCalled();
	});

	it('should paginate commits when a full page is returned', async () => {
		mockGithubAppService.getInstallationToken.mockResolvedValue('token-abc');

		const fullPage = Array.from({ length: 100 }, (_, i) => makeApiCommit(`sha-${i}`));

		mockHttpService.axiosRef.get
			.mockResolvedValueOnce({ data: fullPage })
			.mockResolvedValueOnce({ data: [] })
			.mockResolvedValueOnce({ data: [] });

		mockCommitModel.upsertMany.mockResolvedValue(undefined);

		await processor.process(makeJob('backfill_repo', backfillJobData));

		expect(mockCommitModel.upsertMany).toHaveBeenCalledTimes(1);
	});

	it('should paginate PRs when a full page is returned', async () => {
		mockGithubAppService.getInstallationToken.mockResolvedValue('token-abc');

		const fullPrPage = Array.from({ length: 100 }, (_, i) => makeApiPr(i, i + 1));

		mockHttpService.axiosRef.get
			.mockResolvedValueOnce({ data: [] })
			.mockResolvedValueOnce({ data: fullPrPage })
			.mockResolvedValue({ data: [] });

		mockContributorModel.upsert.mockResolvedValue(undefined);
		mockPullRequestModel.upsert.mockResolvedValue(mockPr);
		mockCommitModel.upsertMany.mockResolvedValue(undefined);

		await processor.process(makeJob('backfill_repo', backfillJobData));

		expect(mockPullRequestModel.upsert).toHaveBeenCalledTimes(100);
	});
});

